    let curlyDepth = 0;

    for (let index = 0; index < text.length; index += 1) {
      const char = text[index];
      const prev = index > 0 ? text[index - 1] : '';
      const next = index + 1 < text.length ? text[index + 1] : '';

      if (char === "'" && !inDouble) {
        if (inSingle && next === "'") {
          index += 1;
          continue;
        }
        inSingle = !inSingle;
        continue;
      }

      if (char === '"' && !inSingle && prev !== '\\') {
        inDouble = !inDouble;
        continue;
      }

      if (inSingle || inDouble) continue;

      if (char === '[') squareDepth += 1;
      else if (char === ']') squareDepth = Math.max(0, squareDepth - 1);
      else if (char === '{') curlyDepth += 1;
      else if (char === '}') curlyDepth = Math.max(0, curlyDepth - 1);
      else if (char === ',' && squareDepth === 0 && curlyDepth === 0) {
        const item = text.slice(start, index).trim();
        if (item) items.push(item);
        start = index + 1;
      }
    }

    const tail = text.slice(start).trim();
    if (tail) items.push(tail);
    return items;
  }

  function parseQuotedString(text) {
    if (text.startsWith('"') && text.endsWith('"')) {
      try {
        return JSON.parse(text);
      } catch {
        return text.slice(1, -1).replace(/\\"/g, '"').replace(/\\\\/g, '\\');
      }
    }

    if (text.startsWith("'") && text.endsWith("'")) {
      return text.slice(1, -1).replace(/''/g, "'");
    }

    return text;
  }

  function parseScalar(raw) {
    const text = String(raw ?? '').trim();
    if (!text) return '';
    if (text === '[]') return [];
    if (text === '{}') return {};
    if (
      (text.startsWith('"') && text.endsWith('"')) ||
      (text.startsWith("'") && text.endsWith("'"))
    ) {
      return parseQuotedString(text);
    }
    if (text.startsWith('[') && text.endsWith(']')) {
      return splitFlowItems(text.slice(1, -1)).map((item) => parseScalar(item));
    }
    if (text.startsWith('{') && text.endsWith('}')) {
      const output = {};
      for (const part of splitFlowItems(text.slice(1, -1))) {
        const mapping = splitKeyValue(part);
        if (!mapping) continue;
        output[String(parseScalar(mapping.key))] = parseScalar(mapping.value);
      }
      return output;
    }
    if (/^(?:null|Null|NULL|~)$/.test(text)) return null;
    if (/^(?:true|True|TRUE)$/.test(text)) return true;
    if (/^(?:false|False|FALSE)$/.test(text)) return false;
    if (/^-?(?:0|[1-9]\d*)(?:\.\d+)?(?:[eE][+-]?\d+)?$/.test(text)) return Number(text);
    return text;
  }

  function parseKey(raw) {
    const text = String(raw ?? '').trim();
    const value = parseScalar(text);
    return typeof value === 'string' ? value : String(value);
  }

  function readBlockScalar(lines, startIndex, parentIndent, style) {
    const parts = [];
    let blockIndent = null;
    let index = startIndex;

    while (index < lines.length) {
      const line = lines[index];
      if (!line.trim()) {
        if (blockIndent !== null) parts.push('');
        index += 1;
        continue;
      }

      const indent = countIndent(line);
      if (indent <= parentIndent) break;
      if (blockIndent === null) blockIndent = indent;
      parts.push(line.slice(blockIndent));
      index += 1;
    }

    let value = '';
    if (style === '>') {
      const paragraphs = [];
      let current = [];
      for (const part of parts) {
        if (part === '') {
          if (current.length) {
            paragraphs.push(current.join(' '));
            current = [];
          }
          paragraphs.push('');
        } else {
          current.push(part.trim());
        }
      }
      if (current.length) paragraphs.push(current.join(' '));
      value = paragraphs.join('\n').trim();
    } else {
      value = parts.join('\n').trim();
    }

    return {
      value,
      nextIndex: index,
    };
  }

  function skipEmpty(lines, state) {
    while (state.index < lines.length && !lines[state.index].trim()) {
      state.index += 1;
    }
  }

  function assignMappingValue(target, keyRaw, valueRaw, lines, state, parentIndent) {
    const key = parseKey(keyRaw);
    const valueText = String(valueRaw ?? '').trim();

    if (valueText.startsWith('|')) {
      const block = readBlockScalar(lines, state.index, parentIndent, '|');
      target[key] = block.value;
      state.index = block.nextIndex;
      return;
    }

    if (valueText.startsWith('>')) {
      const block = readBlockScalar(lines, state.index, parentIndent, '>');
      target[key] = block.value;
      state.index = block.nextIndex;
      return;
    }

    if (!valueText) {
      const childIndent = nextMeaningfulIndent(lines, state.index);
      target[key] = childIndent !== null && childIndent > parentIndent
        ? parseNode(lines, state, childIndent)
        : {};
      return;
    }

    target[key] = parseScalar(valueText);
  }

  function parseSequence(lines, state, indent) {
    const output = [];

    while (state.index < lines.length) {
      skipEmpty(lines, state);
      if (state.index >= lines.length) break;

      const line = lines[state.index];
      const lineIndent = countIndent(line);
      const trimmed = line.slice(lineIndent);
      if (lineIndent < indent || lineIndent !== indent || !trimmed.startsWith('-')) break;

      const content = trimmed.length === 1 ? '' : trimmed.slice(1).trimStart();
      state.index += 1;

      if (!content) {
        const childIndent = nextMeaningfulIndent(lines, state.index);
        output.push(
          childIndent !== null && childIndent > lineIndent
            ? parseNode(lines, state, childIndent)
            : null,
        );
        continue;
      }

      const mapping = splitKeyValue(content);
      if (mapping && mapping.key) {
        const entry = {};
        assignMappingValue(entry, mapping.key, mapping.value, lines, state, lineIndent);
        const childIndent = nextMeaningfulIndent(lines, state.index);
        if (childIndent !== null && childIndent > lineIndent) {
          Object.assign(entry, parseMapping(lines, state, childIndent));
        }
        output.push(entry);
      } else {
        output.push(parseScalar(content));
      }
    }

    return output;
  }

  function parseMapping(lines, state, indent) {
    const output = {};

    while (state.index < lines.length) {
      skipEmpty(lines, state);
      if (state.index >= lines.length) break;

      const line = lines[state.index];
      const lineIndent = countIndent(line);
      const trimmed = line.slice(lineIndent);
      if (lineIndent < indent || lineIndent !== indent || trimmed.startsWith('-')) break;

      const mapping = splitKeyValue(trimmed);
      state.index += 1;
      if (!mapping || !mapping.key) continue;
      assignMappingValue(output, mapping.key, mapping.value, lines, state, lineIndent);
    }

    return output;
  }

  function parseNode(lines, state, indent) {
    skipEmpty(lines, state);
    if (state.index >= lines.length) return null;

    const line = lines[state.index];
    const lineIndent = countIndent(line);
    if (lineIndent < indent) return null;
    const trimmed = line.slice(lineIndent);
    return trimmed.startsWith('-')
      ? parseSequence(lines, state, indent)
      : parseMapping(lines, state, indent);
  }

  function parseYamlDocument(rawText) {
    const text = normalizeText(rawText);
    if (!text) return {};
    const lines = text.split('\n');
    const state = { index: 0 };
    const initialIndent = nextMeaningfulIndent(lines, 0) ?? 0;
    const document = parseNode(lines, state, initialIndent);
    return document && typeof document === 'object' ? document : {};
  }

  class OpenApiCompactor {
    constructor(spec, includeDescriptions = false) {
      this.spec = spec || {};
      this.includeDescriptions = includeDescriptions;
      this.resolvedRefs = new Map();
      this.schemaCache = new Map();
      this.referencedSchemaNames = new Set();
    }

    compact() {
      const output = { ops: this.compactOperations() };
      const api = this.compactInfo();
      const defs = this.compactComponentSchemas();
      if (Object.keys(api).length) output.api = api;
      if (Object.keys(defs).length) output.defs = defs;
      return output;
    }

    compactInfo() {
      const components = this.spec.components || {};
      const securitySchemes = components.securitySchemes || {};
      const output = {};

      const auth = {};
      for (const [name, scheme] of Object.entries(securitySchemes)) {
        auth[name] = this.compactSecurityScheme(scheme);
      }
      if (Object.keys(auth).length) output.auth = auth;

      const globalSecurity = this.compactSecurity(this.spec.security);
      if (globalSecurity !== null) output.security = globalSecurity;

      return output;
    }

    compactSecurityScheme(scheme) {
      const resolved = this.resolveIfRef(scheme) || {};
      const type = resolved.type || 'unknown';

      if (type === 'http') {
        let value = type;
        if (resolved.scheme) value += ':' + resolved.scheme;
        if (resolved.bearerFormat) value += ':' + resolved.bearerFormat;
        return value;
      }

      if (type === 'apiKey') {
        return 'apiKey:' + (resolved.in || '?') + ':' + (resolved.name || '?');
      }

      if (type === 'oauth2') {
        const flows = resolved.flows || {};
        return { oauth2: Object.keys(flows).sort() };
      }

      if (type === 'openIdConnect') return 'openIdConnect';
      return type;
    }

    compactSecurity(security) {
      if (security === undefined || security === null) return null;
      if (Array.isArray(security) && security.length === 0) return [];
      if (!Array.isArray(security)) return null;

      return security.map((requirement) => {
        const item = {};
        for (const [name, scopes] of Object.entries(requirement || {})) {
          item[name] = Array.isArray(scopes) ? scopes : [];
        }
        return item;
      });
    }

    compactOperations() {
      const operations = {};
      const paths = this.spec.paths || {};
      const httpMethods = new Set(['get', 'post', 'put', 'patch', 'delete', 'options', 'head', 'trace']);

      for (const [pathName, pathItem] of Object.entries(paths)) {
        const resolvedPathItem = this.resolveIfRef(pathItem) || {};
        const sharedParameters = Array.isArray(resolvedPathItem.parameters)
          ? resolvedPathItem.parameters
          : [];

        for (const [method, operation] of Object.entries(resolvedPathItem)) {
          if (!httpMethods.has(String(method).toLowerCase())) continue;

          const resolvedOperation = this.resolveIfRef(operation) || {};
          const key = String(method).toUpperCase() + ' ' + pathName;
          const output = {};

          const security = this.compactSecurity(resolvedOperation.security);
          if (security !== null) output.security = security;

          const params = this.compactParameters(sharedParameters, resolvedOperation.parameters || []);
          if (Object.keys(params).length) output.params = params;

          const requestBody = this.compactRequestBody(resolvedOperation.requestBody);
          if (requestBody) output.body = requestBody;

          const responses = this.compactResponses(resolvedOperation.responses || {});
          if (Object.keys(responses).length) output.res = responses;

          operations[key] = output;
        }
      }

      return operations;
    }

    compactParameters(sharedParameters, localParameters) {
      const merged = new Map();

      for (const parameter of [...(sharedParameters || []), ...(localParameters || [])]) {
        const resolved = this.resolveIfRef(parameter) || {};
        const name = resolved.name;
        const location = resolved.in;
        if (!name || !location) continue;
        merged.set(location + '::' + name, resolved);
      }

      const output = {};
      for (const parameter of merged.values()) {
        const location = parameter.in;
        const name = parameter.required ? parameter.name : parameter.name + '?';
        if (!output[location]) output[location] = {};
        const summary = parameter.schema ? this.compactSchema(parameter.schema) : 'any';

        if (this.includeDescriptions && parameter.description) {
          output[location][name] = {
            t: summary,
            d: this.cleanText(parameter.description),
          };
        } else {
          output[location][name] = summary;
        }
      }

      return output;
    }

    compactRequestBody(requestBody) {
      if (!requestBody) return null;

      const resolved = this.resolveIfRef(requestBody) || {};
      const output = {};
      if (resolved.required) output.req = true;

      const content = this.compactContent(resolved.content || {});
      if (Object.keys(content).length) output.content = content;

      if (this.includeDescriptions && resolved.description) {
        output.d = this.cleanText(resolved.description);
      }

      return Object.keys(output).length ? output : null;
    }

    compactResponses(responses) {
      const output = {};

      for (const [statusCode, response] of Object.entries(responses || {})) {
        const resolved = this.resolveIfRef(response) || {};
        const item = {};

        const content = this.compactContent(resolved.content || {});
        if (Object.keys(content).length) item.content = content;

        const headers = this.compactHeaders(resolved.headers || {});
        if (Object.keys(headers).length) item.headers = headers;

        output[String(statusCode)] = Object.keys(item).length ? item : 'response';
      }

      return output;
    }

    compactHeaders(headers) {
      const output = {};
      for (const [name, header] of Object.entries(headers || {})) {
        const resolved = this.resolveIfRef(header) || {};
        output[name] = resolved.schema ? this.compactSchema(resolved.schema) : 'any';
      }
      return output;
    }

    compactContent(content) {
      const output = {};
      for (const [contentType, mediaType] of Object.entries(content || {})) {
        const resolved = this.resolveIfRef(mediaType) || {};
        let entry = resolved.schema ? this.compactSchema(resolved.schema) : 'any';

        if (this.includeDescriptions) {
          if (resolved.example !== undefined) {
            entry = { schema: entry, example: resolved.example };
          } else if (resolved.examples) {
            entry = { schema: entry, examples: Object.keys(resolved.examples).sort() };
          }
        }

        output[contentType] = entry;
      }
      return output;
    }

    compactComponentSchemas() {
      const schemas = (((this.spec || {}).components || {}).schemas) || {};
      const output = {};
      const queue = Array.from(this.referencedSchemaNames);
      const visited = new Set();

      while (queue.length) {
        const name = queue.shift();
        if (!name || visited.has(name) || !schemas[name]) continue;
        visited.add(name);
        output[name] = this.compactSchema(schemas[name], name);

        for (const referencedName of this.referencedSchemaNames) {
          if (!visited.has(referencedName) && !queue.includes(referencedName)) {
            queue.push(referencedName);
          }
        }
      }

      return output;
    }

    compactSchema(schema, name = null) {
      if (schema === undefined || schema === null) return 'any';

      if (schema && typeof schema === 'object' && schema.$ref) {
        return this.refLabel(schema.$ref);
      }

      const resolved = this.resolveIfRef(schema);
      if (!resolved || typeof resolved !== 'object') return 'any';

      if (name && this.schemaCache.has(name)) {
        return this.schemaCache.get(name);
      }

      let result;
      if (Array.isArray(resolved.allOf)) {
        result = { allOf: resolved.allOf.map((item) => this.compactSchema(item)) };
      } else if (Array.isArray(resolved.oneOf)) {
        result = { oneOf: resolved.oneOf.map((item) => this.compactSchema(item)) };
      } else if (Array.isArray(resolved.anyOf)) {
        result = { anyOf: resolved.anyOf.map((item) => this.compactSchema(item)) };
      } else if (resolved.type === 'array' || resolved.items) {
        result = [this.compactSchema(resolved.items)];
      } else if (this.looksLikeObjectSchema(resolved)) {
        result = this.compactObjectSchema(resolved);
      } else {
        result = this.compactScalarSchema(resolved);
      }

      result = this.applyNullable(result, resolved);
      if (name) this.schemaCache.set(name, result);
      return result;
    }

    compactObjectSchema(schema) {
      const properties = schema.properties || {};
      const required = new Set(Array.isArray(schema.required) ? schema.required : []);
      const output = {};

      for (const [propertyName, propertySchema] of Object.entries(properties)) {
        const key = required.has(propertyName) ? propertyName : propertyName + '?';
        output[key] = this.compactSchema(propertySchema);
      }

      if (schema.additionalProperties) {
        output['*'] = schema.additionalProperties === true
          ? 'any'
          : this.compactSchema(schema.additionalProperties);
      }

      if (!Object.keys(output).length) {
        return 'object';
      }

      if (this.includeDescriptions && schema.description) {
        return {
          type: output,
          d: this.cleanText(schema.description),
        };
      }

      return output;
    }

    compactScalarSchema(schema) {
      let value = schema.type || 'any';
      if (schema.format) value += ':' + schema.format;
      if (Array.isArray(schema.enum) && schema.enum.length) {
        value += '[' + schema.enum.map((item) => JSON.stringify(item)).join(',') + ']';
      }
      return value;
    }

    applyNullable(result, schema) {
      if (!schema.nullable) return result;
      if (typeof result === 'string') return result + '|null';
      return { nullable: result };
    }

    looksLikeObjectSchema(schema) {
      return schema.type === 'object' || schema.properties || schema.additionalProperties;
    }

    resolveIfRef(node) {
      if (!node || typeof node !== 'object') return node;
      if (!node.$ref) return node;

      const ref = node.$ref;
      if (this.resolvedRefs.has(ref)) {
        return this.resolvedRefs.get(ref);
      }

      let target = this.spec;
      for (const rawPart of String(ref).replace(/^#\//, '').split('/')) {
        const part = rawPart.replace(/~1/g, '/').replace(/~0/g, '~');
        target = target ? target[part] : undefined;
      }

      const resolved = this.resolveIfRef(target);
      this.resolvedRefs.set(ref, resolved);
      return resolved;
    }

    refLabel(ref) {
      const normalizedRef = String(ref || '');
      const parts = normalizedRef.split('/');
      const label = parts[parts.length - 1];
      if (normalizedRef.startsWith('#/components/schemas/') && label) {
        this.referencedSchemaNames.add(label);
      }
      return '@' + label;
    }

    cleanText(value) {
      return String(value || '').split(/\s+/).filter(Boolean).join(' ');
    }
  }

  let requirements = null;
  let openapi = null;

  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) {
      requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements.md');
    }
    if (!openapi) {
      openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi.yaml');
    }
  }

  if (!requirements) {
    throw new Error('Requirements binary is missing, cannot compact backend context.');
  }
  if (!openapi) {
    throw new Error('OpenAPI binary is missing, cannot compact backend context.');
  }

  const requirementsText = compactRequirementsText(requirements.text);
  if (!requirementsText) {
    throw new Error('Requirements text is empty after compaction.');
  }

  const openapiRaw = normalizeText(openapi.text || '');
  if (!openapiRaw) {
    throw new Error('OpenAPI text is empty, cannot compact specification.');
  }

  let parsedSpec;
  if (openapiRaw.startsWith('{')) {
    try {
      parsedSpec = JSON.parse(openapiRaw);
    } catch {
      parsedSpec = parseYamlDocument(openapiRaw);
    }
  } else {
    parsedSpec = parseYamlDocument(openapiRaw);
  }

  if (!parsedSpec || typeof parsedSpec !== 'object' || !Object.keys(parsedSpec).length) {
    throw new Error('Failed to parse OpenAPI document into a compactable object.');
  }

  const compactedSpec = new OpenApiCompactor(parsedSpec, false).compact();
  const compactedText = JSON.stringify(compactedSpec);

  return [{
    json: {},
    binary: {
      requirements: {
        data: Buffer.from(requirementsText, 'utf8').toString('base64'),
        mimeType: 'text/plain',
        fileExtension: 'txt',
        fileName: 'requirements-compact.txt',
      },
      openapiSpec: {
        data: Buffer.from(compactedText, 'utf8').toString('base64'),
        mimeType: 'application/json',
        fileExtension: 'json',
        fileName: 'openapi-compact.json',
      },
    },
  }];
}

return await beCompactContextArtifacts.call(this);

function beInitGenerationState() {
  const item = $input.first();
  if (!item) {
    throw new Error('No backend structure item received.');
  }

  const json = item.json || {};
  const structure = json.backendStructureObject || JSON.parse(String(json.backendStructure || '{}'));
  if (!Array.isArray(structure.files) || !structure.files.length) {
    throw new Error('Backend structure does not contain any files.');
  }

  const seen = new Set();
  const files = structure.files.map((file, index) => {
    const filePath = typeof file === 'string'
      ? String(file).trim()
      : String(file?.path || '').trim();
    if (!filePath.startsWith('backend/')) {
      throw new Error(`Invalid backend structure path at index ${index}: ${filePath || '<empty>'}`);
    }
    if (seen.has(filePath)) {
      throw new Error(`Duplicate backend structure path: ${filePath}`);
    }
    seen.add(filePath);
    return { path: filePath };
  });

  return [{
    json: {
      ...json,
      allPlannedFiles: files,
      remainingFiles: files,
      generatedFiles: [],
      generatedFilePaths: [],
      lastIterationFiles: [],
      totalPlannedFiles: files.length,
      generatedFileCountTotal: 0,
      remainingFileCount: files.length,
      batchSize: 15,
      currentBatchFiles: files.slice(0, 15),
      currentBatchFileCount: Math.min(files.length, 15),
      iteration: 1,
      hasRemainingFiles: 'yes',
    },
    binary: item.binary ?? {},
  }];
}

return beInitGenerationState();

async function beInitRefinementState() {
  const item = $input.first();
  if (!item) throw new Error('No backend refinement context item received.');

  function normalizeFiles(value) {
    const files = Array.isArray(value) ? value : [];
    return files.map((entry) => {
      if (typeof entry === 'string') return { path: entry.trim() };
      if (entry && typeof entry === 'object') return { path: String(entry.path ?? '').trim() };
      return { path: '' };
    }).filter((entry) => entry.path);
  }

  function decodeBinaryText(binaryEntry) {
    try {
      const raw = String(binaryEntry?.data ?? '');
      return raw && raw !== 'filesystem-v2' ? Buffer.from(raw, 'base64').toString('utf8') : '';
    } catch {
      return '';
    }
  }

  async function readBinaryText(binary, propertyName, binaryEntry) {
    try {
      if (typeof this?.helpers?.getBinaryDataBuffer === 'function') {
        const index = Array.isArray($input?.all?.()) ? 0 : 0;
        const buffer = await this.helpers.getBinaryDataBuffer(index, propertyName);
        if (buffer) return buffer.toString('utf8');
      }
    } catch {}
    return decodeBinaryText(binaryEntry);
  }

  function uniquePaths(paths) {
    const seen = new Set();
    const output = [];
    for (const value of paths || []) {
      const path = String(value?.path ?? value ?? '').trim();
      if (!path || seen.has(path)) continue;
      seen.add(path);
      output.push({ path });
    }
    return output;
  }

  function parseStructure(text) {
    const raw = String(text ?? '').trim();
    if (!raw) return null;
    try {
      const parsed = JSON.parse(raw);
      const files = normalizeFiles(parsed?.files);
      return files.length ? { files } : null;
    } catch {
      return null;
    }
  }

  function normalizeBackendPath(rawPath, backendRoot, rawDirectory) {
    const normalizedRoot = String(backendRoot || 'backend').replace(/\\/g, '/').trim().replace(/\/+$/, '') || 'backend';
    const directory = String(rawDirectory ?? '').replace(/\\/g, '/').trim().replace(/^\.\//, '').replace(/\/+$/, '');
    const fileName = String(rawPath ?? '').replace(/\\/g, '/').trim().replace(/^\.\//, '');
    const combined = [directory, fileName]
      .filter(Boolean)
      .join('/')
      .replace(/\/+/g, '/')
      .replace(/^\.\//, '')
      .replace(/\/+/g, '/');
    if (!combined) return '';
    if (combined === normalizedRoot || combined === normalizedRoot + '.zip') return '';
    if (combined.startsWith(normalizedRoot + '/')) return combined;
    return normalizedRoot + '/' + combined.replace(/^\/+/, '');
  }

  async function collectCurrentBackendFiles(binary, backendRoot) {
    const byPath = new Map();
    for (const [propertyName, entry] of Object.entries(binary || {})) {
      if (propertyName === 'backendZip' || propertyName === 'backendStructure') continue;
      const fileName = String(entry?.fileName ?? '').trim();
      const normalizedPath = normalizeBackendPath(fileName, backendRoot, entry?.directory);
      const isDecompressedEntry = /^current_/i.test(propertyName) || String(entry?.directory ?? '').replace(/\\/g, '/').trim() === backendRoot;
      if ((!isDecompressedEntry && !normalizedPath.startsWith(backendRoot + '/')) || !normalizedPath || normalizedPath.endsWith('.zip')) continue;
      byPath.set(normalizedPath, { path: normalizedPath, content: await readBinaryText(binary, propertyName, entry) });
    }
    return Array.from(byPath.values()).sort((a, b) => a.path.localeCompare(b.path));
  }

  const json = item.json || {};
  const binary = item.binary || {};
  const rawPlanEntries = Array.isArray(json.refinementPlanFiles) ? json.refinementPlanFiles : (Array.isArray(json.files) ? json.files : []);
  const allowedActions = new Set(['modify', 'create', 'remove']);
  const seenPlanPaths = new Set();
  const refinementPlanFiles = [];
  for (const entry of rawPlanEntries) {
    if (!entry || typeof entry !== 'object') continue;
    const path = String(entry.path ?? '').trim();
    const action = String(entry.action ?? '').trim().toLowerCase();
    if (!path.startsWith('backend/') || !allowedActions.has(action) || seenPlanPaths.has(path)) continue;
    seenPlanPaths.add(path);
    refinementPlanFiles.push({ path, action });
  }
  if (!refinementPlanFiles.length) {
    throw new Error('Backend refinement plan did not contain any valid file actions.');
  }

  const backendRoot = String(json.backendRoot ?? 'backend').trim() || 'backend';
  const backendFiles = await collectCurrentBackendFiles.call(this, binary, backendRoot);
  if (!backendFiles.length) {
    throw new Error('Current backend ZIP could not be unpacked into files for refinement.');
  }
  const backendFileMap = new Map(backendFiles.map((file) => [file.path, file]));
  const structureTextCandidates = [
    String(json.backendStructure ?? '').trim(),
    String(json.structurePlan ?? '').trim(),
    decodeBinaryText(binary.backendStructure),
  ].filter(Boolean);
  const parsedStructure = structureTextCandidates.map(parseStructure).find(Boolean);
  const currentPlanFiles = uniquePaths(parsedStructure?.files?.length ? parsedStructure.files : backendFiles.map((file) => ({ path: file.path })));

  const removePaths = new Set(refinementPlanFiles.filter((file) => file.action === 'remove').map((file) => file.path));
  const workItems = refinementPlanFiles
    .filter((file) => file.action !== 'remove')
    .map((file) => ({ path: file.path, action: file.action, currentExists: backendFileMap.has(file.path) }));

  const currentBackendFiles = backendFiles.filter((file) => !removePaths.has(file.path));
  const currentPlanPaths = currentPlanFiles.filter((file) => !removePaths.has(file.path));
  for (const workItem of workItems) {
    if (!currentPlanPaths.some((file) => file.path === workItem.path)) currentPlanPaths.push({ path: workItem.path });
  }

  const batchSize = Math.max(1, Number(json.refinementBatchSize ?? 4));
  const currentBatchFiles = workItems.slice(0, batchSize);
  const backendStructureObject = { files: currentPlanPaths };
  const backendStructure = JSON.stringify(backendStructureObject);

  return [{
    json: {
      ...json,
      refinementPlanFiles,
      removeFilePaths: Array.from(removePaths),
      generatedFiles: currentBackendFiles,
      generatedFilePaths: currentBackendFiles.map((file) => file.path),
      generatedFileCountTotal: currentBackendFiles.length,
      currentPlanFiles: currentPlanPaths,
      plannedFiles: currentPlanPaths,
      backendStructure,
      backendStructureObject,
      remainingFiles: workItems,
      remainingFileCount: workItems.length,
      currentBatchFiles,
      currentBatchFileCount: currentBatchFiles.length,
      allPlannedFiles: currentPlanPaths,
      allowedOutputFiles: currentBatchFiles.map((file) => ({ path: file.path })),
      lastIterationFiles: [],
      recentImplementationSummaries: [],
      generatedImplementationIndex: [],
      batchSize,
      iteration: 1,
      hasRemainingFiles: workItems.length > 0 ? 'yes' : 'no',
    },
    binary,
  }];
}

return beInitRefinementState();

